import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.data.elasticsearch.core.ElasticsearchRestTemplate;
import org.springframework.data.elasticsearch.core.SearchHit;
import org.springframework.data.elasticsearch.core.SearchHits;
import org.springframework.data.elasticsearch.core.query.NativeSearchQueryBuilder;
import org.springframework.data.elasticsearch.core.query.Query;
import org.springframework.data.elasticsearch.core.query.SearchQuery;
import org.springframework.stereotype.Service;

@Service
public class ProductService {

    @Autowired
    private ElasticsearchRestTemplate elasticsearchTemplate;

    public void indexProduct(Product product) {
        elasticsearchTemplate.save(product);
    }

    public SearchHits<Product> searchProducts(String query) {
        Query searchQuery = new NativeSearchQueryBuilder()
                .withQuery(QueryBuilders.queryStringQuery(query))
                .build();
        return elasticsearchTemplate.search(searchQuery, Product.class);
    }

    public SearchHits<Product> searchProductsByFacet(String query, String facetField) {
        Query searchQuery = new NativeSearchQueryBuilder()
                .withQuery(QueryBuilders.queryStringQuery(query))
                .addAggregation(AggregationBuilders.terms("by_" + facetField).field(facetField))
                .build();
        return elasticsearchTemplate.search(searchQuery, Product.class);
    }
}